import { describe, it, expect, vi, beforeEach } from 'vitest';
import * as vscode from 'vscode';
import { DeleteFilesAction } from '../../../src/extension/actions/deleteFiles';

vi.mock('vscode', () => ({
  workspace: {
    fs: {
      readFile: vi.fn(),
      writeFile: vi.fn().mockResolvedValue(undefined),
      delete: vi.fn().mockResolvedValue(undefined),
    },
    getConfiguration: vi.fn(),
  },
  window: {
    showErrorMessage: vi.fn(),
  },
  Uri: {
    joinPath: vi.fn((base: { fsPath: string }, ...pathSegments: string[]) => ({
      fsPath: `${base.fsPath}/${pathSegments.join('/')}`,
      toString: () => `file://${base.fsPath}/${pathSegments.join('/')}`,
    })),
  },
  ConfigurationTarget: {
    Global: 1,
    Workspace: 2,
    WorkspaceFolder: 3,
  },
}));

describe('DeleteFilesAction', () => {
  const mockWorkspaceFolder = { fsPath: '/workspace' } as vscode.Uri;
  let mockRefreshGraph: ReturnType<typeof vi.fn>;
  let mockConfigUpdate: ReturnType<typeof vi.fn>;
  let currentFavorites: string[];

  beforeEach(() => {
    vi.clearAllMocks();
    mockRefreshGraph = vi.fn().mockResolvedValue(undefined);
    currentFavorites = [];

    vi.mocked(vscode.workspace.fs.readFile).mockResolvedValue(
      new Uint8Array([72, 101, 108, 108, 111])
    );
    vi.mocked(vscode.workspace.fs.delete).mockResolvedValue(undefined);
    vi.mocked(vscode.workspace.fs.writeFile).mockResolvedValue(undefined);

    mockConfigUpdate = vi.fn().mockResolvedValue(undefined);
    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue({
      get: vi.fn((key: string, defaultValue: unknown) => {
        if (key === 'favorites') return [...currentFavorites];
        return defaultValue;
      }),
      update: mockConfigUpdate,
    } as unknown as vscode.WorkspaceConfiguration);
  });

  describe('description', () => {
    it('describes a single file deletion using the filename', () => {
      const action = new DeleteFilesAction(['src/utils/helper.ts'], mockWorkspaceFolder, mockRefreshGraph);
      expect(action.description).toBe('Delete: helper.ts');
    });

    it('describes multiple file deletions with a count', () => {
      const action = new DeleteFilesAction(['a.ts', 'b.ts', 'c.ts'], mockWorkspaceFolder, mockRefreshGraph);
      expect(action.description).toBe('Delete 3 files');
    });

    it('describes two file deletions with a count', () => {
      const action = new DeleteFilesAction(['a.ts', 'b.ts'], mockWorkspaceFolder, mockRefreshGraph);
      expect(action.description).toBe('Delete 2 files');
    });
  });

  describe('execute', () => {
    it('reads file contents before deletion for backup', async () => {
      const action = new DeleteFilesAction(['src/app.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();

      expect(vscode.workspace.fs.readFile).toHaveBeenCalledOnce();
      expect(vscode.workspace.fs.delete).toHaveBeenCalledWith(
        expect.objectContaining({ fsPath: '/workspace/src/app.ts' }),
        { useTrash: true }
      );
    });

    it('handles multiple files', async () => {
      const action = new DeleteFilesAction(
        ['src/a.ts', 'src/b.ts', 'src/c.ts'],
        mockWorkspaceFolder,
        mockRefreshGraph
      );

      await action.execute();

      expect(vscode.workspace.fs.readFile).toHaveBeenCalledTimes(3);
      expect(vscode.workspace.fs.delete).toHaveBeenCalledTimes(3);
    });

    it('continues with other files when one read fails', async () => {
      vi.mocked(vscode.workspace.fs.readFile)
        .mockRejectedValueOnce(new Error('not found'))
        .mockResolvedValueOnce(new Uint8Array([1, 2, 3]));

      const action = new DeleteFilesAction(
        ['missing.ts', 'exists.ts'],
        mockWorkspaceFolder,
        mockRefreshGraph
      );

      await action.execute();

      // Should still refresh graph even if one file failed
      expect(mockRefreshGraph).toHaveBeenCalledOnce();
    });

    it('removes deleted files from favorites', async () => {
      currentFavorites = ['src/app.ts', 'src/other.ts'];

      const action = new DeleteFilesAction(['src/app.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();

      expect(mockConfigUpdate).toHaveBeenCalledWith(
        'favorites',
        ['src/other.ts'],
        undefined,
      );
    });

    it('does not change favorites when deleted files are not favorites', async () => {
      currentFavorites = ['src/other.ts'];

      const action = new DeleteFilesAction(['src/app.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();

      // Still updates config with the same favorites list
      expect(mockConfigUpdate).toHaveBeenCalledWith(
        'favorites',
        ['src/other.ts'],
        undefined,
      );
    });

    it('stores favorites state before deletion', async () => {
      currentFavorites = ['src/app.ts', 'src/keep.ts'];

      const action = new DeleteFilesAction(['src/app.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();
      await action.undo();

      // Undo should restore the original favorites
      const lastUpdateCall = mockConfigUpdate.mock.calls[mockConfigUpdate.mock.calls.length - 1];
      expect(lastUpdateCall[1]).toEqual(['src/app.ts', 'src/keep.ts']);
    });

    it('calls refreshGraph after deletion', async () => {
      const action = new DeleteFilesAction(['app.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();

      expect(mockRefreshGraph).toHaveBeenCalledOnce();
    });
  });

  describe('undo', () => {
    it('restores file contents from backup', async () => {
      const fileContent = new Uint8Array([72, 101, 108, 108, 111]);
      vi.mocked(vscode.workspace.fs.readFile).mockResolvedValue(fileContent);

      const action = new DeleteFilesAction(['src/app.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();
      await action.undo();

      expect(vscode.workspace.fs.writeFile).toHaveBeenCalledWith(
        expect.objectContaining({ fsPath: '/workspace/src/app.ts' }),
        fileContent
      );
    });

    it('restores favorites to the state before execute', async () => {
      currentFavorites = ['src/app.ts', 'src/other.ts'];

      const action = new DeleteFilesAction(['src/app.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();
      await action.undo();

      const lastCall = mockConfigUpdate.mock.calls[mockConfigUpdate.mock.calls.length - 1];
      expect(lastCall[0]).toBe('favorites');
      expect(lastCall[1]).toEqual(['src/app.ts', 'src/other.ts']);
    });

    it('shows error message when file restoration fails', async () => {
      const action = new DeleteFilesAction(['src/app.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();

      vi.mocked(vscode.workspace.fs.writeFile).mockRejectedValueOnce(new Error('write error'));

      await action.undo();

      expect(vscode.window.showErrorMessage).toHaveBeenCalledWith(
        'Failed to restore src/app.ts'
      );
    });

    it('calls refreshGraph after restoration', async () => {
      const action = new DeleteFilesAction(['app.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();
      mockRefreshGraph.mockClear();
      await action.undo();

      expect(mockRefreshGraph).toHaveBeenCalledOnce();
    });

    it('restores multiple files', async () => {
      const action = new DeleteFilesAction(
        ['src/a.ts', 'src/b.ts'],
        mockWorkspaceFolder,
        mockRefreshGraph
      );

      await action.execute();
      await action.undo();

      expect(vscode.workspace.fs.writeFile).toHaveBeenCalledTimes(2);
    });
  });
});

/**
 * @fileoverview Additional tests for DeleteFilesAction targeting surviving mutants.
 *
 * Surviving mutants:
 * - L26,28,30 ArrayDeclaration: initial _storedFiles/_favoritesBefore/_favoritesAfter = []
 * - L54:54 StringLiteral: config section 'codegraphy'
 * - L55:67 ArrayDeclaration: default [] in config.get('favorites', [])
 * - L68:23 BlockStatement: catch body emptied (console.error skipped)
 * - L69:23, L87:23 StringLiteral: template literals for error messages
 * - L93:54 StringLiteral: config section 'codegraphy' in undo
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import * as vscode from 'vscode';
import { DeleteFilesAction } from '../../../src/extension/actions/deleteFiles';

vi.mock('vscode', () => ({
  workspace: {
    fs: {
      readFile: vi.fn(),
      writeFile: vi.fn().mockResolvedValue(undefined),
      delete: vi.fn().mockResolvedValue(undefined),
    },
    getConfiguration: vi.fn(),
  },
  window: {
    showErrorMessage: vi.fn(),
  },
  Uri: {
    joinPath: vi.fn((base: { fsPath: string }, ...pathSegments: string[]) => ({
      fsPath: `${base.fsPath}/${pathSegments.join('/')}`,
      toString: () => `file://${base.fsPath}/${pathSegments.join('/')}`,
    })),
  },
  ConfigurationTarget: {
    Global: 1,
    Workspace: 2,
    WorkspaceFolder: 3,
  },
}));

describe('DeleteFilesAction (mutant coverage)', () => {
  const mockWorkspaceFolder = { fsPath: '/workspace' } as vscode.Uri;
  let mockRefreshGraph: ReturnType<typeof vi.fn>;
  let mockConfigGet: ReturnType<typeof vi.fn>;
  let mockConfigUpdate: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    vi.clearAllMocks();
    mockRefreshGraph = vi.fn().mockResolvedValue(undefined);
    mockConfigGet = vi.fn().mockReturnValue([]);
    mockConfigUpdate = vi.fn().mockResolvedValue(undefined);

    vi.mocked(vscode.workspace.fs.readFile).mockResolvedValue(
      new Uint8Array([72, 101, 108, 108, 111])
    );
    vi.mocked(vscode.workspace.fs.delete).mockResolvedValue(undefined);
    vi.mocked(vscode.workspace.fs.writeFile).mockResolvedValue(undefined);

    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue({
      get: mockConfigGet,
      update: mockConfigUpdate,
    } as unknown as vscode.WorkspaceConfiguration);
  });

  describe('config section string', () => {
    it('calls getConfiguration with codegraphy during execute', async () => {
      const action = new DeleteFilesAction(['file.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();

      expect(vscode.workspace.getConfiguration).toHaveBeenCalledWith('codegraphy');
    });

    it('calls getConfiguration with codegraphy during undo', async () => {
      const action = new DeleteFilesAction(['file.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();
      vi.mocked(vscode.workspace.getConfiguration).mockClear();
      vi.mocked(vscode.workspace.getConfiguration).mockReturnValue({
        get: mockConfigGet,
        update: mockConfigUpdate,
      } as unknown as vscode.WorkspaceConfiguration);

      await action.undo();

      expect(vscode.workspace.getConfiguration).toHaveBeenCalledWith('codegraphy');
    });
  });

  describe('config get key and default value', () => {
    it('reads the favorites key with an empty array default', async () => {
      const action = new DeleteFilesAction(['file.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();

      expect(mockConfigGet).toHaveBeenCalledWith('favorites', []);
    });
  });

  describe('config update key', () => {
    it('updates the favorites config key during execute', async () => {
      const action = new DeleteFilesAction(['file.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();

      expect(mockConfigUpdate).toHaveBeenCalledWith(
        'favorites',
        expect.any(Array),
        undefined,
      );
    });

    it('updates the favorites config key during undo', async () => {
      const action = new DeleteFilesAction(['file.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();
      mockConfigUpdate.mockClear();
      await action.undo();

      expect(mockConfigUpdate).toHaveBeenCalledWith(
        'favorites',
        expect.any(Array),
        undefined,
      );
    });
  });

  describe('initial state arrays are empty', () => {
    it('undo restores an empty favorites list when favorites were originally empty', async () => {
      mockConfigGet.mockReturnValue([]);
      const action = new DeleteFilesAction(['file.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();
      await action.undo();

      // The last config update call (in undo) should restore empty favorites
      const undoCall = mockConfigUpdate.mock.calls[mockConfigUpdate.mock.calls.length - 1];
      expect(undoCall[1]).toEqual([]);
    });

    it('undo without prior execute restores empty stored files list', async () => {
      const action = new DeleteFilesAction(['file.ts'], mockWorkspaceFolder, mockRefreshGraph);

      // Undo without execute: _storedFiles should be [] so no writeFile calls happen
      await action.undo();

      expect(vscode.workspace.fs.writeFile).not.toHaveBeenCalled();
    });

    it('undo without prior execute uses empty favoritesBefore', async () => {
      const action = new DeleteFilesAction(['file.ts'], mockWorkspaceFolder, mockRefreshGraph);

      // Undo without execute: _favoritesBefore should be [] (empty default)
      await action.undo();

      expect(mockConfigUpdate).toHaveBeenCalledWith(
        'favorites',
        [],
        undefined,
      );
    });

    it('execute stores empty favoritesAfter when no favorites match deleted paths', async () => {
      mockConfigGet.mockReturnValue([]);
      const action = new DeleteFilesAction(['file.ts'], mockWorkspaceFolder, mockRefreshGraph);

      await action.execute();

      // favoritesAfter should be [] since original favorites were empty
      expect(mockConfigUpdate).toHaveBeenCalledWith(
        'favorites',
        [],
        undefined,
      );
    });
  });

  describe('error handling in execute catch block', () => {
    it('logs an error message with the failing file path when readFile throws', async () => {
      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});
      const error = new Error('read failure');
      vi.mocked(vscode.workspace.fs.readFile).mockRejectedValue(error);

      const action = new DeleteFilesAction(
        ['broken.ts'],
        mockWorkspaceFolder,
        mockRefreshGraph
      );

      await action.execute();

      expect(consoleSpy).toHaveBeenCalledWith(
        '[CodeGraphy] Failed to delete broken.ts:',
        error
      );
      consoleSpy.mockRestore();
    });

    it('includes the specific file path in the execute error log', async () => {
      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});
      vi.mocked(vscode.workspace.fs.readFile).mockRejectedValue(new Error('fail'));

      const action = new DeleteFilesAction(
        ['src/deep/nested/file.ts'],
        mockWorkspaceFolder,
        mockRefreshGraph
      );

      await action.execute();

      const logCall = consoleSpy.mock.calls[0];
      expect(logCall[0]).toContain('src/deep/nested/file.ts');
      consoleSpy.mockRestore();
    });

    it('continues processing remaining files after a failure', async () => {
      vi.spyOn(console, 'error').mockImplementation(() => {});
      vi.mocked(vscode.workspace.fs.readFile)
        .mockRejectedValueOnce(new Error('fail'))
        .mockResolvedValueOnce(new Uint8Array([1, 2, 3]));

      const action = new DeleteFilesAction(
        ['fail.ts', 'success.ts'],
        mockWorkspaceFolder,
        mockRefreshGraph
      );

      await action.execute();

      // The second file should still be deleted
      expect(vscode.workspace.fs.delete).toHaveBeenCalledTimes(1);
      expect(vscode.workspace.fs.delete).toHaveBeenCalledWith(
        expect.objectContaining({ fsPath: '/workspace/success.ts' }),
        { useTrash: true }
      );

      vi.mocked(console.error).mockRestore?.();
    });
  });

  describe('error handling in undo catch block', () => {
    it('logs an error message with the file path when writeFile fails during undo', async () => {
      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});
      const action = new DeleteFilesAction(
        ['restore-fail.ts'],
        mockWorkspaceFolder,
        mockRefreshGraph
      );

      await action.execute();
      consoleSpy.mockClear();

      const writeError = new Error('write error');
      vi.mocked(vscode.workspace.fs.writeFile).mockRejectedValueOnce(writeError);

      await action.undo();

      expect(consoleSpy).toHaveBeenCalledWith(
        '[CodeGraphy] Failed to restore restore-fail.ts:',
        writeError
      );
      consoleSpy.mockRestore();
    });

    it('shows an error notification with the file path when undo restore fails', async () => {
      vi.spyOn(console, 'error').mockImplementation(() => {});
      const action = new DeleteFilesAction(
        ['notify-fail.ts'],
        mockWorkspaceFolder,
        mockRefreshGraph
      );

      await action.execute();
      vi.mocked(vscode.workspace.fs.writeFile).mockRejectedValueOnce(new Error('fail'));

      await action.undo();

      expect(vscode.window.showErrorMessage).toHaveBeenCalledWith(
        'Failed to restore notify-fail.ts'
      );
      vi.mocked(console.error).mockRestore?.();
    });
  });

  describe('favoritesAfter calculation', () => {
    it('removes deleted file paths from the favorites list', async () => {
      mockConfigGet.mockReturnValue(['keep.ts', 'delete-me.ts', 'also-keep.ts']);

      const action = new DeleteFilesAction(
        ['delete-me.ts'],
        mockWorkspaceFolder,
        mockRefreshGraph
      );

      await action.execute();

      expect(mockConfigUpdate).toHaveBeenCalledWith(
        'favorites',
        ['keep.ts', 'also-keep.ts'],
        undefined,
      );
    });
  });
});

/**
 * @fileoverview Additional tests for RenameFileAction targeting surviving mutants.
 *
 * Surviving mutants:
 * - L18:40, L20:39 ArrayDeclaration: initial _favoritesBefore/_favoritesAfter = []
 * - L46:54 StringLiteral: config section 'codegraphy' in execute
 * - L47:64 ArrayDeclaration: default [] in config.get('favorites', [])
 * - L82:56 StringLiteral: config section 'codegraphy' in undo
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import * as vscode from 'vscode';
import { RenameFileAction } from '../../../src/extension/actions/renameFile';

vi.mock('vscode', () => ({
  workspace: {
    fs: {
      rename: vi.fn().mockResolvedValue(undefined),
    },
    getConfiguration: vi.fn(),
  },
  Uri: {
    joinPath: vi.fn((base: { fsPath: string }, ...pathSegments: string[]) => ({
      fsPath: `${base.fsPath}/${pathSegments.join('/')}`,
      toString: () => `file://${base.fsPath}/${pathSegments.join('/')}`,
    })),
  },
  ConfigurationTarget: {
    Global: 1,
    Workspace: 2,
    WorkspaceFolder: 3,
  },
}));

describe('RenameFileAction (mutant coverage)', () => {
  const mockWorkspaceFolder = { fsPath: '/workspace' } as vscode.Uri;
  let mockRefreshGraph: ReturnType<typeof vi.fn>;
  let mockConfigGet: ReturnType<typeof vi.fn>;
  let mockConfigUpdate: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    vi.clearAllMocks();
    mockRefreshGraph = vi.fn().mockResolvedValue(undefined);
    mockConfigGet = vi.fn().mockReturnValue([]);
    mockConfigUpdate = vi.fn().mockResolvedValue(undefined);

    vi.mocked(vscode.workspace.getConfiguration).mockReturnValue({
      get: mockConfigGet,
      update: mockConfigUpdate,
    } as unknown as vscode.WorkspaceConfiguration);
  });

  describe('config section string', () => {
    it('calls getConfiguration with codegraphy during execute', async () => {
      const action = new RenameFileAction(
        'old.ts', 'new.ts', mockWorkspaceFolder, mockRefreshGraph
      );

      await action.execute();

      expect(vscode.workspace.getConfiguration).toHaveBeenCalledWith('codegraphy');
    });

    it('calls getConfiguration with codegraphy during undo when file was favorited', async () => {
      mockConfigGet.mockReturnValue(['old.ts']);
      const action = new RenameFileAction(
        'old.ts', 'new.ts', mockWorkspaceFolder, mockRefreshGraph
      );

      await action.execute();
      vi.mocked(vscode.workspace.getConfiguration).mockClear();
      vi.mocked(vscode.workspace.getConfiguration).mockReturnValue({
        get: mockConfigGet,
        update: mockConfigUpdate,
      } as unknown as vscode.WorkspaceConfiguration);

      await action.undo();

      expect(vscode.workspace.getConfiguration).toHaveBeenCalledWith('codegraphy');
    });
  });

  describe('config get key and default value', () => {
    it('reads the favorites key with an empty array default', async () => {
      const action = new RenameFileAction(
        'old.ts', 'new.ts', mockWorkspaceFolder, mockRefreshGraph
      );

      await action.execute();

      expect(mockConfigGet).toHaveBeenCalledWith('favorites', []);
    });
  });

  describe('config update key', () => {
    it('updates the favorites config key during execute when file is favorited', async () => {
      mockConfigGet.mockReturnValue(['old.ts']);
      const action = new RenameFileAction(
        'old.ts', 'new.ts', mockWorkspaceFolder, mockRefreshGraph
      );

      await action.execute();

      expect(mockConfigUpdate).toHaveBeenCalledWith(
        'favorites',
        expect.any(Array),
        undefined,
      );
    });

    it('updates the favorites config key during undo when file was favorited', async () => {
      mockConfigGet.mockReturnValue(['old.ts']);
      const action = new RenameFileAction(
        'old.ts', 'new.ts', mockWorkspaceFolder, mockRefreshGraph
      );

      await action.execute();
      mockConfigUpdate.mockClear();
      await action.undo();

      expect(mockConfigUpdate).toHaveBeenCalledWith(
        'favorites',
        expect.any(Array),
        undefined,
      );
    });
  });

  describe('initial state arrays are empty', () => {
    it('does not update favorites on undo when the file was never favorited', async () => {
      mockConfigGet.mockReturnValue([]);
      const action = new RenameFileAction(
        'old.ts', 'new.ts', mockWorkspaceFolder, mockRefreshGraph
      );

      await action.execute();
      mockConfigUpdate.mockClear();
      await action.undo();

      // _favoritesBefore is [] and does not include 'old.ts', so no config update
      expect(mockConfigUpdate).not.toHaveBeenCalled();
    });

    it('undo restores correct favorites when file was in favorites', async () => {
