describe('ToggleFavoriteAction', () => {
  let mockConfigUpdate: ReturnType<typeof vi.fn>;
  let currentFavorites: string[];
  let mockSendFavorites: ReturnType<typeof vi.fn>;

  beforeEach(() => {
    vi.clearAllMocks();
