      );
    });

    it('does not write a second legacy exclude key during execute', async () => {
      const action = new AddToExcludeAction(['file.ts'], mockRefreshGraph);

      await action.execute();

      expect(mockConfigUpdate).not.toHaveBeenCalledWith(
